import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';

describe('FileSystemManager', () => {
  let fsManager;
  let testDir;

  beforeEach(async () => {
    // Create a temporary test directory
    testDir = path.join(os.tmpdir(), `fsm-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    fsManager = new FileSystemManager(testDir);
  });

  afterEach(async () => {
    // Clean up test directory
    try {
      await fs.rm(testDir, { recursive: true, force: true });
    } catch (error) {
      // Ignore cleanup errors
    }
  });

  describe('validatePath', () => {
    it('should validate paths within root directory', () => {
      const validPath = fsManager.validatePath('test.txt');
      expect(validPath).toBe(path.join(testDir, 'test.txt'));
    });

    it('should prevent directory traversal attacks', () => {
      expect(() => {
        fsManager.validatePath('../../../etc/passwd');
      }).toThrow('Invalid path');
    });

    it('should handle nested paths correctly', () => {
      const validPath = fsManager.validatePath('src/components/Button.js');
      expect(validPath).toBe(path.join(testDir, 'src/components/Button.js'));
    });
  });

  describe('readFile', () => {
    it('should read file contents', async () => {
      const testFile = 'test.txt';
      const testContent = 'Hello, World!';
      await fs.writeFile(path.join(testDir, testFile), testContent);

      const content = await fsManager.readFile(testFile);
      expect(content).toBe(testContent);
    });

    it('should throw error for non-existent file', async () => {
      await expect(fsManager.readFile('nonexistent.txt')).rejects.toThrow('File not found');
    });

    it('should throw error when trying to read a directory', async () => {
      const dirPath = 'testdir';
      await fs.mkdir(path.join(testDir, dirPath));

      await expect(fsManager.readFile(dirPath)).rejects.toThrow('Path is a directory');
    });
  });

  describe('writeFile', () => {
    it('should write content to a file', async () => {
      const testFile = 'output.txt';
      const testContent = 'Test content';

      await fsManager.writeFile(testFile, testContent);

      const content = await fs.readFile(path.join(testDir, testFile), 'utf8');
      expect(content).toBe(testContent);
    });

    it('should create parent directories if they do not exist', async () => {
      const testFile = 'nested/dir/file.txt';
      const testContent = 'Nested content';

      await fsManager.writeFile(testFile, testContent);

      const content = await fs.readFile(path.join(testDir, testFile), 'utf8');
      expect(content).toBe(testContent);
    });

    it('should overwrite existing files', async () => {
      const testFile = 'overwrite.txt';
      await fs.writeFile(path.join(testDir, testFile), 'Original');

      await fsManager.writeFile(testFile, 'Updated');

      const content = await fs.readFile(path.join(testDir, testFile), 'utf8');
      expect(content).toBe('Updated');
    });
  });

  describe('listDirectory', () => {
    beforeEach(async () => {
      // Create test directory structure
      await fs.mkdir(path.join(testDir, 'subdir'));
      await fs.writeFile(path.join(testDir, 'file1.txt'), 'content1');
      await fs.writeFile(path.join(testDir, 'file2.txt'), 'content2');
      await fs.writeFile(path.join(testDir, 'subdir', 'file3.txt'), 'content3');
    });

    it('should list directory contents non-recursively', async () => {
      const entries = await fsManager.listDirectory('.');

      expect(entries).toHaveLength(3);
      expect(entries.map(e => e.name).sort()).toEqual(['file1.txt', 'file2.txt', 'subdir'].sort());
    });

    it('should list directory contents recursively', async () => {
      const entries = await fsManager.listDirectory('.', true);

      expect(entries.length).toBeGreaterThanOrEqual(4);
      const names = entries.map(e => e.name);
      expect(names).toContain('file1.txt');
      expect(names).toContain('file2.txt');
      expect(names).toContain('subdir');
      expect(names).toContain('file3.txt');
    });

    it('should include isDirectory and isFile flags', async () => {
      const entries = await fsManager.listDirectory('.');

      const file = entries.find(e => e.name === 'file1.txt');
      const dir = entries.find(e => e.name === 'subdir');

      expect(file.isFile).toBe(true);
      expect(file.isDirectory).toBe(false);
      expect(dir.isDirectory).toBe(true);
      expect(dir.isFile).toBe(false);
    });

    it('should throw error for non-existent directory', async () => {
      await expect(fsManager.listDirectory('nonexistent')).rejects.toThrow('Directory not found');
    });
  });

  describe('exists', () => {
    it('should return true for existing file', async () => {
      const testFile = 'exists.txt';
      await fs.writeFile(path.join(testDir, testFile), 'content');

      const exists = await fsManager.exists(testFile);
      expect(exists).toBe(true);
    });

    it('should return false for non-existent file', async () => {
      const exists = await fsManager.exists('nonexistent.txt');
      expect(exists).toBe(false);
    });

    it('should return true for existing directory', async () => {
      const testDirName = 'existsdir';
      await fs.mkdir(path.join(testDir, testDirName));

      const exists = await fsManager.exists(testDirName);
      expect(exists).toBe(true);
    });
  });

  describe('getStats', () => {
    it('should return file statistics', async () => {
      const testFile = 'stats.txt';
      const testContent = 'Test content for stats';
      await fs.writeFile(path.join(testDir, testFile), testContent);

      const stats = await fsManager.getStats(testFile);

      expect(stats.size).toBe(testContent.length);
      expect(stats.isFile).toBe(true);
      expect(stats.isDirectory).toBe(false);
      expect(stats.modified).toBeDefined();
      expect(stats.created).toBeDefined();
    });

    it('should return directory statistics', async () => {
      const testDirName = 'statsdir';
      await fs.mkdir(path.join(testDir, testDirName));

      const stats = await fsManager.getStats(testDirName);

      expect(stats.isDirectory).toBe(true);
      expect(stats.isFile).toBe(false);
    });

    it('should throw error for non-existent file', async () => {
      await expect(fsManager.getStats('nonexistent.txt')).rejects.toThrow('File not found');
    });
  });

  describe('isBinary', () => {
    it('should detect text files as non-binary', async () => {
      const testFile = 'text.txt';
      const testContent = 'This is a text file with normal content.';
      await fs.writeFile(path.join(testDir, testFile), testContent);

      const isBinary = await fsManager.isBinary(testFile);
      expect(isBinary).toBe(false);
    });

    it('should detect binary files', async () => {
      const testFile = 'binary.bin';
      // Create a buffer with null bytes (binary indicator)
      const binaryContent = Buffer.from([0x00, 0x01, 0x02, 0x03, 0x04, 0x05]);
      await fs.writeFile(path.join(testDir, testFile), binaryContent);

      const isBinary = await fsManager.isBinary(testFile);
      expect(isBinary).toBe(true);
    });

    it('should handle JavaScript files as non-binary', async () => {
      const testFile = 'script.js';
      const testContent = 'function hello() { console.log("Hello, World!"); }';
      await fs.writeFile(path.join(testDir, testFile), testContent);

      const isBinary = await fsManager.isBinary(testFile);
      expect(isBinary).toBe(false);
    });

    it('should return false for directories', async () => {
      const testDirName = 'binarydir';
      await fs.mkdir(path.join(testDir, testDirName));

      const isBinary = await fsManager.isBinary(testDirName);
      expect(isBinary).toBe(false);
    });

    it('should throw error for non-existent file', async () => {
      await expect(fsManager.isBinary('nonexistent.bin')).rejects.toThrow('File not found');
    });
  });

  describe('gitignore support', () => {
    beforeEach(async () => {
      // Create a .gitignore file
      const gitignoreContent = `
node_modules/
*.log
.env
dist/
build/
`;
      await fs.writeFile(path.join(testDir, '.gitignore'), gitignoreContent);
      
      // Recreate fsManager to load .gitignore
      fsManager = new FileSystemManager(testDir);
      await fsManager.loadGitignore();
    });

    it('should detect ignored files', () => {
      // Files inside ignored directories
      expect(fsManager.shouldIgnore('node_modules/package.json', false)).toBe(true);
      expect(fsManager.shouldIgnore('dist/bundle.js', false)).toBe(true);
      
      // Direct file matches
      expect(fsManager.shouldIgnore('error.log', false)).toBe(true);
      expect(fsManager.shouldIgnore('.env', false)).toBe(true);
      
      // Directory names themselves
      expect(fsManager.shouldIgnore('node_modules', true)).toBe(true);
      expect(fsManager.shouldIgnore('dist', true)).toBe(true);
    });

    it('should not ignore non-matching files', () => {
      expect(fsManager.shouldIgnore('src/index.js')).toBe(false);
      expect(fsManager.shouldIgnore('README.md')).toBe(false);
      expect(fsManager.shouldIgnore('package.json')).toBe(false);
    });

    it('should filter ignored files from array', () => {
      const files = [
        'src/index.js',
        'node_modules/package.json',
        'error.log',
        'README.md',
        '.env',
        'dist/bundle.js'
      ];

      const filtered = fsManager.filterIgnored(files);
      
      expect(filtered).toEqual([
        'src/index.js',
        'README.md'
      ]);
    });

    it('should respect ignore patterns in listDirectory', async () => {
      // Create test structure
      await fs.mkdir(path.join(testDir, 'src'));
      await fs.mkdir(path.join(testDir, 'node_modules'));
      await fs.writeFile(path.join(testDir, 'src', 'index.js'), 'code');
      await fs.writeFile(path.join(testDir, 'node_modules', 'package.json'), '{}');
      await fs.writeFile(path.join(testDir, 'error.log'), 'error');
      await fs.writeFile(path.join(testDir, 'README.md'), 'readme');

      // Debug: check if patterns are working
      expect(fsManager.shouldIgnore('node_modules', true)).toBe(true);
      expect(fsManager.shouldIgnore('error.log', false)).toBe(true);

      const entries = await fsManager.listDirectory('.', false, true);
      const names = entries.map(e => e.name);

      // Check that non-ignored files are present
      expect(names).toContain('src');
      expect(names).toContain('README.md');
      
      // Check that ignored files are not present
      expect(names.includes('node_modules')).toBe(false);
      expect(names.includes('error.log')).toBe(false);
    });

    it('should allow listing without respecting ignore patterns', async () => {
      // Create test structure
      await fs.mkdir(path.join(testDir, 'node_modules'));
      await fs.writeFile(path.join(testDir, 'error.log'), 'error');

      const entries = await fsManager.listDirectory('.', false, false);
      const names = entries.map(e => e.name);

      expect(names).toContain('node_modules');
      expect(names).toContain('error.log');
    });
  });
});
